package main

import (
	"bufio"
	"fmt"
	"os"
)

type Pos struct {
	row, collum int
}

func siege(board[][]byte, r, c int) {
	if (r == 0 || c == 0 ) || (r ==len(board) || c == len(board[0])) {
		return
	}

	if board[r][c] == 'O' {
		if board[r+1][c] == 'X' && board[r-1][c] == 'X' && board[r][c+1] == 'X' && board[r][c-1] == 'X' {
			board[r][c] = 'X'
		}
	}
	siege(board, r+1, c)

}
// NÃO ALTERE A ASSINATURA DA FUNÇÃO solve
func solve(board [][]byte) {
	siege(board, 0, 0)
}

// NÃO ALTERE A MAIN
func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Scan()
	var nrows, ncols int
	fmt.Sscanf(scanner.Text(), "%d %d", &nrows, &ncols)
	board := make([][]byte, nrows)
	for i := 0; i < nrows; i++ {
		scanner.Scan()
		board[i] = []byte(scanner.Text())
	}
	solve(board)
	for _, row := range board {
		fmt.Println(string(row))
	}
}
